const trigger = $('Execute Workflow Trigger').first().json;
const query = trigger.query || '';

const qdrantResponse = $input.first().json;
const hits = qdrantResponse.result || [];

if (hits.length === 0) {
  return [{ json: { result: `No internal documents found matching: "${query}".` } }];
}

const passages = hits
  .filter(h => (h.score || 0) > 0.25)
  .map(h => {
    const p = h.payload || {};
    const date = p.date_created ? new Date(p.date_created).toISOString().split('T')[0] : 'unknown';
    const dealRef = p.deal_id ? ` | deal: ${p.company_name || p.deal_id}` : (p.service_line ? ` | service: ${p.service_line}` : '');
    return `[${p.doc_type || 'document'}, ${date}${dealRef}, score: ${(h.score || 0).toFixed(3)}]\n${p.page_content || '(no content)'}`.trim();
  });

if (passages.length === 0) {
  return [{ json: { result: `Found ${hits.length} internal results but all scored below relevance threshold (0.25). Try a more specific query.` } }];
}

const result = `## Internal RAG Results — "${query}"\n\nFound ${passages.length} relevant passage(s):\n\n${passages.join('\n\n---\n\n')}`;

return [{ json: { result } }];
